from langchain.schema.output_parser import OutputParserException
from langchain.agents.output_parsers import OpenAIFunctionsAgentOutputParser

output_parser = OpenAIFunctionsAgentOutputParser()

def validate_agent_output(text: str):
    try:
        parsed = output_parser.parse(text)
        if not hasattr(parsed, 'tool_calls') or len(parsed.tool_calls) == 0:
            print('Warning: No structured tool calls detected')
        return True
    except OutputParserException:
        print('Error: Malformed agent output')
        return False
